fn main() {
    let greeting = "Hello, Rust world!";

    // Find and extract a word
    if let Some(start) = greeting.find("Rust") {
        let end = start + 4;
        let word = &greeting[start..end];
        println!("Found: {}", word);
    }

    // Split and process
    for word in greeting.split_whitespace() {
        println!("Word: {}", word);
    }
}
